# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session

app = Flask(__name__)
app.secret_key = 'your_secret_key'

@app.route('/update_profile', methods=['POST'])
def update_profile():
    if not session.get('user_id'):
        return jsonify({'error': 'Unauthorized'}), 401

    user_data = request.json
    email = user_data.get('email')
    password = user_data.get('password')
    enable_2fa = user_data.get('enable_2fa')

    # Here you would typically update the user's profile in your database
    # For demonstration, we'll just print the new settings
    print(f"Updating profile for user {session['user_id']}:")
    if email:
        print(f"New Email: {email}")
    if password:
        print("Password updated (not shown here for security reasons)")
    if enable_2fa is not None:
        print(f"2FA Enabled: {enable_2fa}")

    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)